# DSE筆記系統 安裝腳本
# 使用方法：
# 1. 將此檔案儲存為 "安裝DSE.ps1"（注意編碼選 UTF-8）
# 2. 右鍵點擊此檔案 →「使用 PowerShell 執行」
# 3. 檔案會自動出現在桌面！
#
# 如果無法執行，先在 PowerShell 輸入：
# Set-ExecutionPolicy -Scope CurrentUser RemoteSigned

$b64 = @"
"@

Write-Host "正在建立 DSE 筆記系統..."
$bytes = [System.Convert]::FromBase64String($b64)
$ms = New-Object System.IO.MemoryStream(,$bytes)
$gz = New-Object System.IO.Compression.GZipStream($ms, [System.IO.Compression.CompressionMode]::Decompress)
$sr = New-Object System.IO.StreamReader($gz, [System.Text.Encoding]::UTF8)
$html = $sr.ReadToEnd()
$sr.Close()
$gz.Close()
$ms.Close()

$outPath = [System.IO.Path]::Combine([Environment]::GetFolderPath("Desktop"), "DSE筆記系統.html")
[System.IO.File]::WriteAllText($outPath, $html, (New-Object System.Text.UTF8Encoding $true))

Write-Host ""
Write-Host "========================================" -ForegroundColor Green
Write-Host "  安裝完成！" -ForegroundColor Green
Write-Host "  檔案位置：$outPath" -ForegroundColor Cyan
Write-Host "  雙擊桌面上的 DSE筆記系統.html 即可使用" -ForegroundColor Yellow
Write-Host "========================================" -ForegroundColor Green
Write-Host ""
Write-Host "按任意鍵關閉..." -ForegroundColor Gray
$null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
